            SAXSource saxSource = new SAXSource(xmlReader, new InputSource(fis));

            // Perform the transformation from SAX source to DOM result
            // This will throw an exception if the XML format is invalid
            transformer.transform(saxSource, domResult);
        } catch (Exception e) {
            // Provide a foundation for subsequent error handling
            throw new Exception("Failed to parse XML configuration: " + e.getMessage(), e);
        }

        return (Document) domResult.getNode();
    }
}
